// Integration Tests
describe('Integration Tests', () => {
  test('should create complete TextClock activity', () => {
    const bundle = new BundleAdapter();
    bundle.put('timeZone', 'Asia/Shanghai');
    
    const textView = new TextViewAdapter('TimeZone');
    const button = new ButtonAdapter('Get Time Zone');
    const events = new EventAdapter();
    
    events.setOnClickListener('tzBtn', () => {
      const tz = TimeZoneAdapter.getDefault();
      textView.setText(`Zone: ${tz.getDisplayName()}`);
    });
    
    button.setOnClickListener(() => events.triggerClick('tzBtn'));
    button.performClick();
    
    expect(textView.getText()).toContain('Zone:');
  });

  test('should handle activity lifecycle', () => {
    const bundle = new BundleAdapter();
    bundle.put('key', 'value');
    
    // Simulate onCreate
    const textView = new TextViewAdapter();
    textView.setText('Created');
    
    // Simulate onResume
    textView.setText('Resumed');
    
    expect(textView.getText()).toBe('Resumed');
    expect(bundle.getString('key')).toBe('value');
  });
});

